event ERC7579ExecutorOperationExecuted(
    address indexed account,
    bytes32 salt,
    bytes32 mode,
    bytes executionCalldata
);

require(
    totalSigners >= currentThreshold,
    ERC7579MultisigUnreachableThreshold(
        uint64(totalSigners), // Safe cast. Economically impossible to overflow.
        currentThreshold
    )
);

if (!presigned(account, signer, hash) && signer.isValidSignatureNow(hash, signature)) {
    _presigned[account][signer][hash] = true;
    emit ERC7579MultisigStoragePresigned(account, hash, signer);
}

event UserOperationSponsored(
    bytes32 indexed userOpHash,
    address indexed token,
    uint256 tokenAmount,
    uint256 tokenPrice
);

if (prefunder == guarantor) {
    emit UserOperationGuaranteed(userOpHash, prefunder, prefundAmount);
}

assembly ("memory-safe") {
    value := mul(success, calldataload(add(attribute.offset, 0x04)))
    gasLimit := mul(success, calldataload(add(attribute.offset, 0x24)))
    refundRecipient := mul(success, calldataload(add(attribute.offset, 0x44)))
}

$._proposalDetails[proposalId] = ProposalDetails({
    targets: targets,
    values: values,
    calldatas: calldatas,
    descriptionHash: keccak256(bytes(description))
});

if (_isScheduleSet(oldSchedule)) {
    // Emit for implicit cancellations when another default admin was scheduled.
    emit DefaultAdminTransferCanceled();
}

struct TargetConfig {
    mapping(bytes4 selector => uint64 roleId) allowedRoles;
    Time.Delay adminDelay;
    bool closed;
}

if (opts.defender.useDefenderDeploy) {
    return DefenderDeploy.deploy(contractName, constructorData, opts.defender);
} else {
    return _deploy(contractName, constructorData);
}

return
            Core.deploy(
                "TransparentUpgradeableProxy.sol:TransparentUpgradeableProxy",
                abi.encode(impl, initialOwner, initializerData),
                opts
            );
